const app = document.getElementById('app');
const genres = [...new Set(REVIEWS.flatMap(r => r.genre.split(',').map(g => g.trim())).filter(Boolean))].sort();
const latestDate = REVIEWS[0].reviewDate;
const archiveYears = [...new Set(REVIEWS.map(r => String(new Date(r.reviewDate).getFullYear())))].sort((a,b)=>b-a);

function escapeHtml(str) {
  return str.replace(/[&<>"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
}
function ratingValue(stars) { return (stars.match(/★/g) || []).length; }
PLACEHOLDER
function card(review) {
  return `<a class="card review-card" href="#/review/${review.slug}">
    <div class="kicker">${review.genre.split(',')[0]} review</div>
    <h3>${review.title}</h3>
    <div class="mini-meta">
      <span>${review.releaseYear}</span><span>•</span>
      <span>${review.reviewDate}</span><span>•</span>
      <span>${review.rating}</span>
    </div>
    <p class="muted">${escapeHtml(review.review.slice(0, 165).trim())}…</p>
  </a>`;
}
function setActiveNav(name) {
  document.querySelectorAll('[data-nav]').forEach(link => link.classList.toggle('active', link.dataset.nav === name));
}
