function aboutView() {
  setActiveNav('about');
  app.innerHTML = `
    <section class="container review-layout">
      <article class="card review-body">
        <div class="kicker">About the site</div>
        <h1>Mara Vale</h1>
        <p class="lead">Mara Vale is the fictional sole editor and critic behind <em>The Late Screening</em>, a small, rigorously maintained review site she updates after weekday press screenings and late weekend repertory runs.</p>
        <p>Raised in Bristol and now based in Manchester, Mara started the site after years of writing capsule notes in the margins of festival brochures and train tickets. Her taste runs toward patient direction, exact performances, and films that know the difference between seriousness and self-importance. She is skeptical of bloated prestige cinema, fond of neglected genre pictures, and unusually attentive to how editing and score change the moral temperature of a scene.</p>
        <p>The voice of the site reflects that sensibility: measured, conversational, occasionally severe, but never interested in the easy dunk. Mara’s reviews are meant to feel like the thoughtful argument you keep replaying after a screening, when the images are still settling and the stronger details begin to separate themselves from the noise.</p>
      </article>
      <aside class="card">
        <div class="kicker">Editorial habits</div>
        <p class="quote">“A good review should tell you how a film moves, not just what it’s about.”</p>
        <div class="info-row"><span class="info-label">Base</span><div>Manchester, UK</div></div>
        <div class="info-row"><span class="info-label">Favorite beat</span><div>The walk home after a festival screening</div></div>
        <div class="info-row"><span class="info-label">What she notices first</span><div>Blocking, rhythm, and whether the score is doing too much</div></div>
        <div class="info-row"><span class="info-label">Site policy</span><div>No fake enthusiasm anywhere</div></div>
      </aside>
    </section>`;
}

function archiveView() {
  setActiveNav('archive');
  app.innerHTML = `
    <section class="container">
      <div class="card">
        <div class="kicker">Archive</div>
        <h1>Every review in one place</h1>
        <p class="lead">Search by title, then narrow by genre, review year, or minimum rating.</p>
        <div class="filters">
          <div>
            <label class="label" for="search">Search title or director</label>
            <input id="search" type="search" placeholder="Search reviews…">
          </div>
          <div>
            <label class="label" for="genre">Genre</label>
            <select id="genre"><option value="">All genres</option>${genres.map(g => `<option>${g}</option>`).join('')}</select>
          </div>
          <div>
            <label class="label" for="year">Review year</label>
            <select id="year"><option value="">All years</option>${archiveYears.map(y => `<option>${y}</option>`).join('')}</select>
          </div>
          <div>
            <label class="label" for="rating">Minimum rating</label>
            <select id="rating"><option value="">Any</option><option value="2">★★ and up</option><option value="3">★★★ and up</option><option value="4">★★★★ and up</option><option value="5">★★★★★ only</option></select>
          </div>
        </div>
        <div class="result-summary"><span id="results-count"></span><button id="reset-filters">Reset filters</button></div>
        <div class="archive-grid" id="archive-results"></div>
      </div>
    </section>`;
  const els = {
    search: document.getElementById('search'), genre: document.getElementById('genre'),
    year: document.getElementById('year'), rating: document.getElementById('rating'),
    results: document.getElementById('archive-results'), count: document.getElementById('results-count')
  };
  function renderResults() {
    const term = els.search.value.trim().toLowerCase();
    const genre = els.genre.value;
    const year = els.year.value;
    const rating = Number(els.rating.value || 0);
    const filtered = REVIEWS.filter(r => {
      const matchesTerm = !term || r.title.toLowerCase().includes(term) || r.director.toLowerCase().includes(term);
      const matchesGenre = !genre || r.genre.split(',').map(g => g.trim()).includes(genre);
      const matchesYear = !year || String(new Date(r.reviewDate).getFullYear()) === year;
      const matchesRating = !rating || ratingValue(r.rating) >= rating;
      return matchesTerm && matchesGenre && matchesYear && matchesRating;
    });
    els.count.textContent = `${filtered.length} review${filtered.length === 1 ? '' : 's'} shown`;
    els.results.innerHTML = filtered.length ? filtered.map(card).join('') : `<div class="card empty-state"><h3>No matches</h3><p class="muted">Try a broader title search or clear one of the filters.</p></div>`;
  }
  Object.values(els).slice(0,4).forEach(el => el.addEventListener('input', renderResults));
  document.getElementById('reset-filters').addEventListener('click', () => { els.search.value=''; els.genre.value=''; els.year.value=''; els.rating.value=''; renderResults(); });
  renderResults();
}

function reviewView(slug) {
  const review = REVIEWS.find(r => r.slug === slug);
  if (!review) {
    setActiveNav('archive');
    app.innerHTML = `<section class="container"><div class="card empty-state"><h1>Review not found</h1><p class="muted">The link may be broken or the title may have moved.</p><a class="button primary" href="#/archive">Back to archive</a></div></section>`;
    return;
  }
  setActiveNav('archive');
  app.innerHTML = `
    <section class="container review-layout">
      <article class="card review-body">
        <div class="kicker">${review.genre.split(',')[0]} review</div>
        <h1>${review.title}</h1>
        <div class="meta-line">
          <span class="pill">${review.releaseYear}</span>
          <span class="pill">${review.genre}</span>
          <span class="pill">${review.rating}</span>
          <span class="pill">${review.review.split(/\s+/).length} words</span>
        </div>
        <div class="review-text" style="margin-top:1.2rem">${formatReview(review.review)}</div>
      </article>
      <aside class="card">
        <div class="info-row"><span class="info-label">Title</span><div>${review.title}</div></div>
        <div class="info-row"><span class="info-label">Release year</span><div>${review.releaseYear}</div></div>
        <div class="info-row"><span class="info-label">Review date</span><div>${review.reviewDate}</div></div>
        <div class="info-row"><span class="info-label">Genre</span><div>${review.genre}</div></div>
        <div class="info-row"><span class="info-label">Director</span><div>${review.director}</div></div>
        <div class="info-row"><span class="info-label">Rating</span><div>${review.rating}</div></div>
        <div class="info-row"><span class="info-label">Archive</span><div><a href="#/archive">Back to archive</a></div></div>
      </aside>
    </section>`;
}

function router() {
  const hash = location.hash || '#/';
  const [, route, slug] = hash.match(/^#\/([^/]+)?\/?(.*)?$/) || [];
  if (!route) return homeView();
  if (route === 'archive') return archiveView();
  if (route === 'about') return aboutView();
  if (route === 'review') return reviewView(slug);
  return homeView();
}

window.addEventListener('hashchange', router);
window.addEventListener('DOMContentLoaded', router);
